-- =====================================================
-- UPDATE ad_countries - FULL SCHEMA
-- 228 countries from ITExpressLocation.sql
-- Fields: Code, NameVi, NameEn, FullNameVi, FullNameEn,
--         CountryType, CountrySubType, Sovereignty, Capital,
--         CurrencyCode, CurrencyName, PhoneCode, CountryCode3,
--         CountryNumber, InternetCountryCode, Flags
-- =====================================================

USE UniManage;
GO

-- Add new columns if they don't exist
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CountryType')
    ALTER TABLE ad_countries ADD CountryType NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CountrySubType')
    ALTER TABLE ad_countries ADD CountrySubType NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'Sovereignty')
    ALTER TABLE ad_countries ADD Sovereignty NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'Capital')
    ALTER TABLE ad_countries ADD Capital NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CurrencyCode')
    ALTER TABLE ad_countries ADD CurrencyCode NVARCHAR(50) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CurrencyName')
    ALTER TABLE ad_countries ADD CurrencyName NVARCHAR(100) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CountryCode3')
    ALTER TABLE ad_countries ADD CountryCode3 NVARCHAR(10) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'CountryNumber')
    ALTER TABLE ad_countries ADD CountryNumber NVARCHAR(10) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'InternetCountryCode')
    ALTER TABLE ad_countries ADD InternetCountryCode NVARCHAR(50) NULL;
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('ad_countries') AND name = 'Flags')
    ALTER TABLE ad_countries ADD Flags NVARCHAR(100) NULL;
GO

-- Disable foreign key constraints
ALTER TABLE ad_provinces NOCHECK CONSTRAINT ALL;
GO

-- Clear existing data
DELETE FROM ad_countries;
GO

